update
	TB_HMI_CTR_TAG
set FLAG = 1
where
	TAG = #{TAG}
	and TIME = #{TIME}

update
	TB_HMI_CTR_TAG
set FLAG = #{FLAG}
where
	TAG = #{TAG}
	and ANLY_CD = #{ANLY_CD}
	and OPT_IDX = #{OPT_IDX}

mapper.select:
SELECT cppi.PUMP_IDX, cppi.PUMP_GRP, cppi.PUMP_GRP_NM, cppi.PUMP_NM, cppi.PUMP_TYP, rd_pmb.TAGNAME AS PMB_TAGNAME, rd_pri.TAGNAME AS PRI_TAGNAME, MAX(rd_pmb.ts) AS PMB_TS, MAX(rd_pri.ts) AS PRI_TS, CASE WHEN rd_pmb.value = 1 THEN "On" ELSE "Off" END AS PUMP_YN, ROUND(rd_pri.value, 2) AS 'PRI' FROM TB_CTR_PRF_PUMPMST_INF cppi LEFT JOIN TB_RAWDATA rd_pmb ON cppi.PMB_TAG = rd_pmb.TAGNAME AND rd_pmb.TS > DATE_SUB(NOW(), INTERVAL 10 MINUTE) AND rd_pmb.TS <= DATE_ADD(NOW(), INTERVAL 10 MINUTE)
LEFT JOIN TB_RAWDATA rd_pri ON cppi.PRI_T_TAG = rd_pri.TAGNAME AND rd_pri.TS > DATE_SUB(NOW(), INTERVAL 10 MINUTE) AND rd_pri.TS <= DATE_ADD(NOW(), INTERVAL 10 MINUTE)
WHERE cppi.USE_YN = 1 GROUP BY cppi.PUMP_IDX, rd_pmb.TAGNAME, rd_pri.TAGNAME;

WITH RankedPumps AS ( SELECT COALESCE(cpi.OPT_IDX, cpr.OPT_IDX) as OPT_IDX, COALESCE(cpi.PUMP_GRP, cpr.PUMP_GRP ) as PUMP_GRP, cppi.PUMP_GRP_IDX as PUMP_GRP_IDX, COALESCE(cpi.PUMP_IDX, cpr.PUMP_IDX ) as PUMP_IDX, cppi.PUMP_GRP_NM, cppi.PUMP_NM, cppi.PUMP_TYP as PUMP_TYP, IFNULL( COALESCE(cpi.FREQ , cpr.FREQ) , 0) as FREQ, IFNULL( COALESCE(cpi.TUBE_PRSR_PRDCT , cpr.TUBE_PRSR_PRDCT) , 0) as TUBE_PRSR_PRDCT, cppi.CTR_AUTO_TAG, cppi.CTR_AUTO_STOP_TAG, cppi.CTR_AUTO_FREQ_TAG, cppi.CTR_MANUAL_TAG, DATE_FORMAT(COALESCE(cpi.RGSTR_TIME, cpr.RGSTR_TIME), '%Y-%m-%d %H:%i') AS PRDCT_TIME , CASE WHEN COALESCE(cpi.PUMP_YN, cpr.PUMP_YN) = 1 THEN "On" ELSE "Off" END AS PUMP_YN, CASE WHEN COALESCE(cpi.PUMP_YN, cpr.PUMP_YN) = 1 THEN "On" ELSE "Off" END as value, CASE WHEN COALESCE(cpi.PUMP_YN, cpr.PUMP_YN) = 1 THEN 0 ELSE 1 END as PUMP_YN_VALUE, CASE WHEN cpi.OPT_IDX is not null THEN 1 ELSE 0 END as FLAG, COALESCE(cpi.RATE_CTGRY, '') as RATE_CTGRY, COALESCE(cpi.FLOW_CTR, '') as FLOW_CTR, ROW_NUMBER() OVER (PARTITION BY COALESCE(cpi.PUMP_IDX, cpr.PUMP_IDX ) ORDER BY COALESCE(cpi.RGSTR_TIME, cpr.RGSTR_TIME) DESC) as rn FROM TB_CTR_PUMPYN_RST cpr LEFT JOIN TB_CTR_PUMPYN_INQUIRY cpi on cpr.OPT_IDX = cpr.OPT_IDX AND cpi.RGSTR_TIME >= DATE_SUB(NOW(), INTERVAL 10 MINUTE) AND cpr.PUMP_IDX = cpi.PUMP_IDX JOIN TB_CTR_PRF_PUMPMST_INF cppi ON cpr.PUMP_IDX = cppi.PUMP_IDX
and cppi.PUMP_GRP in
#{item}
WHERE cpr.PRDCT_TIME_DIFF = 5 AND cpr.FLAG = 0 AND cpr.RGSTR_TIME >= DATE_SUB(NOW(), INTERVAL 10 MINUTE) ) SELECT * FROM RankedPumps WHERE rn <= 10 ORDER BY PRDCT_TIME DESC, PUMP_IDX ASC;

WITH RankedPumps AS ( SELECT COALESCE(cpi.OPT_IDX, cpr.OPT_IDX) as OPT_IDX, COALESCE(cpi.PUMP_GRP, cpr.PUMP_GRP ) as PUMP_GRP, cppi.PUMP_GRP_IDX as PUMP_GRP_IDX, COALESCE(cpi.PUMP_IDX, cpr.PUMP_IDX ) as PUMP_IDX, cppi.PUMP_GRP_NM, cppi.PUMP_NM, COALESCE(cpi.PUMP_TYP, cpr.PUMP_TYP ) as PUMP_TYP, IFNULL( COALESCE(cpi.FREQ , cpr.FREQ) , 0) as FREQ, ROUND(IFNULL( COALESCE(cpi.TUBE_PRSR_PRDCT , cpr.TUBE_PRSR_PRDCT) , 0),1) as TUBE_PRSR_PRDCT, cppi.CTR_AUTO_TAG, cppi.CTR_AUTO_STOP_TAG, cppi.CTR_AUTO_FREQ_TAG, cppi.CTR_MANUAL_TAG, DATE_FORMAT(COALESCE(cpi.RGSTR_TIME, cpr.RGSTR_TIME), '%Y-%m-%d %H:%i') AS PRDCT_TIME , CASE WHEN COALESCE(cpi.PUMP_YN, cpr.PUMP_YN) = 1 THEN "On" ELSE "Off" END AS PUMP_YN, CASE WHEN COALESCE(cpi.PUMP_YN, cpr.PUMP_YN) = 1 THEN "On" ELSE "Off" END as value, CASE WHEN COALESCE(cpi.PUMP_YN, cpr.PUMP_YN) = 1 THEN 0 ELSE 1 END as PUMP_YN_VALUE, CASE WHEN cpi.OPT_IDX is not null THEN 1 ELSE 0 END as FLAG, COALESCE(cpi.RATE_CTGRY, '') as RATE_CTGRY, COALESCE(cpi.FLOW_CTR, '') as FLOW_CTR, ROW_NUMBER() OVER (PARTITION BY COALESCE(cpi.PUMP_IDX, cpr.PUMP_IDX ) ORDER BY COALESCE(cpi.RGSTR_TIME, cpr.RGSTR_TIME) DESC) as rn FROM TB_CTR_PUMPYN_RST cpr LEFT JOIN TB_CTR_PUMPYN_INQUIRY cpi on cpr.OPT_IDX = cpi.OPT_IDX AND cpi.RGSTR_TIME >= DATE_SUB(NOW(), INTERVAL 10 MINUTE) AND cpr.PUMP_IDX = cpi.PUMP_IDX JOIN TB_CTR_PRF_PUMPMST_INF cppi ON cpr.PUMP_IDX = cppi.PUMP_IDX
and cppi.PUMP_GRP in
#{item}
WHERE cpr.PRDCT_TIME_DIFF = 5 AND cpr.FLAG = 0 AND cpr.RGSTR_TIME >= DATE_SUB(NOW(), INTERVAL 10 MINUTE) ) SELECT * FROM RankedPumps WHERE rn = 1 ORDER BY PRDCT_TIME DESC, PUMP_IDX ASC;

WITH RankedPumps AS ( SELECT COALESCE(cpi.OPT_IDX, cpr.OPT_IDX) as OPT_IDX, COALESCE(cpi.PUMP_GRP, cpr.PUMP_GRP ) as PUMP_GRP, cppi.PUMP_GRP_IDX as PUMP_GRP_IDX, COALESCE(cpi.PUMP_IDX, cpr.PUMP_IDX ) as PUMP_IDX, cppi.PUMP_GRP_NM, cppi.PUMP_NM, cppi.PUMP_TYP as PUMP_TYP, IFNULL( COALESCE(cpi.FREQ , cpr.FREQ) , 0) as FREQ, IFNULL( COALESCE(cpi.TUBE_PRSR_PRDCT , cpr.TUBE_PRSR_PRDCT) , 0) as TUBE_PRSR_PRDCT, cppi.CTR_AUTO_TAG, cppi.CTR_AUTO_STOP_TAG, cppi.CTR_AUTO_FREQ_TAG, cppi.CTR_MANUAL_TAG, DATE_FORMAT(COALESCE(cpi.RGSTR_TIME, cpr.RGSTR_TIME), '%Y-%m-%d %H:%i') AS PRDCT_TIME , CASE WHEN COALESCE(cpi.PUMP_YN, cpr.PUMP_YN) = 1 THEN "On" ELSE "Off" END AS PUMP_YN, CASE WHEN COALESCE(cpi.PUMP_YN, cpr.PUMP_YN) = 1 THEN "On" ELSE "Off" END as value, CASE WHEN COALESCE(cpi.PUMP_YN, cpr.PUMP_YN) = 1 THEN 0 ELSE 1 END as PUMP_YN_VALUE, CASE WHEN cpi.OPT_IDX is not null THEN 1 ELSE 0 END as FLAG, COALESCE(cpi.RATE_CTGRY, '') as RATE_CTGRY, COALESCE(cpi.FLOW_CTR, '') as FLOW_CTR, ROW_NUMBER() OVER (PARTITION BY COALESCE(cpi.PUMP_IDX, cpr.PUMP_IDX ) ORDER BY COALESCE(cpi.RGSTR_TIME, cpr.RGSTR_TIME) DESC) as rn FROM TB_CTR_PUMPYN_RST2 cpr LEFT JOIN TB_CTR_PUMPYN_INQUIRY2 cpi on cpr.OPT_IDX = cpr.OPT_IDX AND cpi.RGSTR_TIME >= DATE_SUB(NOW(), INTERVAL 5 MINUTE) AND cpr.PUMP_IDX = cpi.PUMP_IDX JOIN TB_CTR_PRF_PUMPMST_INF cppi ON cpr.PUMP_IDX = cppi.PUMP_IDX
and cppi.PUMP_GRP in
#{item}
WHERE cpr.PRDCT_TIME_DIFF = 5 AND cpr.FLAG = 0 AND cpr.RGSTR_TIME >= DATE_SUB(NOW(), INTERVAL 60 MINUTE) ) SELECT * FROM RankedPumps WHERE rn = 1 ORDER BY PRDCT_TIME DESC, PUMP_IDX ASC;

WITH LatestRST AS ( SELECT rst.OPT_IDX, rst.PUMP_IDX, rst.PUMP_GRP, rst.FREQ, rst.PUMP_YN, rst.RGSTR_TIME, rst.FLAG, ROW_NUMBER() OVER (PARTITION BY rst.PUMP_IDX ORDER BY rst.RGSTR_TIME DESC) AS rn FROM TB_CTR_PUMPYN_RST AS rst WHERE rst.FLAG = 1
), LatestInquiry AS ( SELECT inquiry.OPT_IDX, inquiry.PUMP_IDX, inquiry.PUMP_GRP, inquiry.FREQ, inquiry.PUMP_YN, inquiry.RGSTR_TIME, inquiry.FLAG, ROW_NUMBER() OVER (PARTITION BY inquiry.PUMP_IDX ORDER BY inquiry.RGSTR_TIME DESC) AS rn FROM TB_CTR_PUMPYN_INQUIRY AS inquiry WHERE inquiry.FLAG = 1
) SELECT COALESCE(li.OPT_IDX, lr.OPT_IDX) AS OPT_IDX, tcppi.PUMP_GRP_IDX AS PUMP_GRP_IDX, tcppi.PUMP_TYP AS PUMP_TYP, tcppi.PUMP_GRP_NM, tcppi.PUMP_NM, COALESCE(li.FREQ, lr.FREQ) AS FREQ, tcppi.CTR_AUTO_TAG, tcppi.CTR_AUTO_STOP_TAG, tcppi.CTR_AUTO_FREQ_TAG, tcppi.CTR_MANUAL_TAG, COALESCE(li.PUMP_GRP, lr.PUMP_GRP) AS PUMP_GRP, DATE_FORMAT(COALESCE(li.RGSTR_TIME, lr.RGSTR_TIME), '%Y-%m-%d %H:%i') AS PRDCT_TIME, COALESCE(li.PUMP_IDX, lr.PUMP_IDX) AS PUMP_IDX, CASE WHEN COALESCE(li.PUMP_YN, lr.PUMP_YN) = 1 THEN "On" ELSE "Off" END AS PUMP_YN,
CASE WHEN li.RGSTR_TIME IS NOT NULL THEN 1 ELSE 0 END AS 'FLAG' FROM LatestRST lr LEFT JOIN LatestInquiry li ON lr.PUMP_IDX = li.PUMP_IDX AND lr.RGSTR_TIME = li.RGSTR_TIME JOIN TB_CTR_PRF_PUMPMST_INF tcppi ON lr.PUMP_IDX = tcppi.PUMP_IDX WHERE lr.rn = 1 ORDER BY lr.RGSTR_TIME DESC, COALESCE(li.PUMP_IDX, lr.PUMP_IDX) ASC;

mapper.update:
update


		TB_CTR_PUMPYN_INQUIRY


		TB_CTR_PUMPYN_RST


set
FLAG = #{FLAG}
where
OPT_IDX = #{OPT_IDX}
and PUMP_IDX = #{PUMP_IDX}
and PUMP_GRP = #{PUMP_GRP}
and PRDCT_TIME_DIFF = 5

mapper.select:
SELECT cppi.PUMP_IDX, cppi.PUMP_GRP, cppi.PUMP_CTR_TYP, latest_data.TAGNAME, latest_data.TS AS 'TS', latest_data.value AS 'value', cpro.STD_VALUE, cpro.REQ_CTR_TAG, cpro.REQ_CTR_STOP_TAG, CASE WHEN latest_data.value = cpro.STD_VALUE THEN 'Close' WHEN latest_data.value = 0 THEN 'Open' ELSE 'None' END AS 'STATUS' FROM TB_CTR_PRF_PUMPMST_INF cppi JOIN TB_CTR_PUMP_REQ_OPT cpro ON cppi.PUMP_IDX = cpro.PUMP_IDX JOIN ( SELECT rd.TAGNAME, rd.TS, rd.value FROM TB_RAWDATA rd WHERE rd.TS = ( SELECT MAX(TS) FROM TB_RAWDATA WHERE TS > DATE_SUB(NOW(), INTERVAL 15 MINUTE) AND TS <= DATE_ADD(NOW(), INTERVAL 5 MINUTE) ) ) AS latest_data ON cpro.REQ_TAG = latest_data.TAGNAME WHERE
cppi.CTR_AUTO_TAG = #{TAG}
cppi.CTR_AUTO_STOP_TAG = #{TAG}
GROUP BY cppi.PUMP_IDX

SELECT cppi.PUMP_IDX, cppi.PUMP_GRP, cppi.PUMP_NM, cppi.PUMP_TYP, rd.TAGNAME, rd.TS AS 'TS', rd.value AS 'value', CASE WHEN rd.value = 1 THEN "On" ELSE "Off" END AS 'STATUS' FROM TB_RAWDATA rd JOIN TB_CTR_PRF_PUMPMST_INF cppi ON rd.TAGNAME = cppi.PMB_TAG WHERE rd.TS = ( SELECT MAX(sub_rd.TS) FROM TB_RAWDATA sub_rd WHERE sub_rd.TAGNAME = cppi.PMB_TAG AND sub_rd.TS >= DATE_SUB(NOW(), INTERVAL 10 MINUTE) )
AND cppi.CTR_AUTO_TAG = #{TAG}
AND cppi.CTR_AUTO_STOP_TAG = #{TAG}

mapper.update:
update TB_WPP_TAG_CODE
set DEFAULT_VALUE = #{value}
where FUNC_TYP = 'SN_MODE'
